/**
 * job-pool.ts  —  400+ curated listings · 20+ countries · 14 fields
 * getDailyJobs() uses a date-based seeded shuffle so a fresh subset surfaces every day.
 */

import { Job } from './mock-data';

function seededShuffle<T>(arr: T[], seed: string): T[] {
  const result = [...arr];
  let h = 0;
  for (let i = 0; i < seed.length; i++) h = (Math.imul(31, h) + seed.charCodeAt(i)) | 0;
  const rng = () => { h ^= h << 13; h ^= h >> 17; h ^= h << 5; return (h >>> 0) / 4294967296; };
  for (let i = result.length - 1; i > 0; i--) { const j = Math.floor(rng() * (i + 1)); [result[i], result[j]] = [result[j], result[i]]; }
  return result;
}

export function getTodayLabel(): string {
  return new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
}

export function getDailyJobs(count = 80): Job[] {
  return seededShuffle(JOB_POOL, new Date().toDateString()).slice(0, count);
}

const d = (n: number) => new Date(Date.now() - 86400000 * n).toISOString();

